import{_ as t,o,c as a,ag as i}from"./chunks/framework.CxZWPeXl.js";const m=JSON.parse('{"title":"Practice Simulation","description":"","frontmatter":{},"headers":[],"relativePath":"en/practice.md","filePath":"en/practice.md"}'),n={name:"en/practice.md"};function r(s,e,l,u,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="practice-simulation" tabindex="-1">Practice Simulation <a class="header-anchor" href="#practice-simulation" aria-label="Permalink to &quot;Practice Simulation&quot;">​</a></h1><blockquote><p>Hone your communication skills through simulated sales conversations with AI customers.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Practice Simulation is the core feature of AI Coach. You interact with an AI-driven virtual customer who responds realistically based on their configured attributes (age, occupation, income, personality traits), creating a safe environment to practice various sales scenarios.</p><h2 id="starting-a-session" tabindex="-1">Starting a Session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a Session&quot;">​</a></h2><ul><li><strong>&quot;Start Conversation&quot;</strong> button on the Dashboard.</li><li><strong>&quot;Redo&quot;</strong> or <strong>&quot;Continue&quot;</strong> buttons in History.</li></ul><hr><h2 id="scenario-selection" tabindex="-1">Scenario Selection <a class="header-anchor" href="#scenario-selection" aria-label="Permalink to &quot;Scenario Selection&quot;">​</a></h2><p>During the setup of a new conversation, you can choose from the following configuration methods:</p><h3 id="pre-configured-personas" tabindex="-1">Pre-configured Personas <a class="header-anchor" href="#pre-configured-personas" aria-label="Permalink to &quot;Pre-configured Personas&quot;">​</a></h3><ul><li>Select from various ready-made persona cards (e.g., &quot;Ms. Fan, 52&quot;).</li><li>Ideal for quick practice sessions.</li></ul><h3 id="custom-persona-settings" tabindex="-1">Custom Persona Settings <a class="header-anchor" href="#custom-persona-settings" aria-label="Permalink to &quot;Custom Persona Settings&quot;">​</a></h3><ul><li>Toggle <strong>&quot;Persona Settings&quot;</strong> to define customer attributes manually (e.g., high-income, married).</li><li>Opens the detailed Customer Persona Setup panel.</li></ul><h3 id="upload-chat-script-new" tabindex="-1">Upload Chat Script (New) <a class="header-anchor" href="#upload-chat-script-new" aria-label="Permalink to &quot;Upload Chat Script (New)&quot;">​</a></h3><ul><li>Toggle <strong>&quot;Upload Chat Script&quot;</strong> to provide a specific context or transcript.</li><li>Allows you to upload a script or specific scenario background for the AI to follow strictly during the simulation journey.</li></ul><h3 id="redo-from-history" tabindex="-1">Redo (From History) <a class="header-anchor" href="#redo-from-history" aria-label="Permalink to &quot;Redo (From History)&quot;">​</a></h3><ul><li>Encounter the exact same customer from a previous session using the Redo button.</li><li>Useful for testing alternative strategies.</li></ul><h3 id="continue-from-history" tabindex="-1">Continue (From History) <a class="header-anchor" href="#continue-from-history" aria-label="Permalink to &quot;Continue (From History)&quot;">​</a></h3><ul><li>Resume an unfinished conversation.</li><li>The customer will faintly remember your previous conversation.</li></ul><hr><h2 id="customer-persona-setup" tabindex="-1">Customer Persona Setup <a class="header-anchor" href="#customer-persona-setup" aria-label="Permalink to &quot;Customer Persona Setup&quot;">​</a></h2><p>When creating a Custom Persona, any blank fields will be automatically filled by the AI.</p><ul><li><strong>Demographics</strong>: Age, Gender, Education, Income, Occupation.</li><li><strong>Personality (MBTI)</strong>: Tremendously influential on communication, objection handling, and decision-making styles.</li><li><strong>Family</strong>: Marital Status, Children Count, Children&#39;s details.</li><li><strong>Relationship</strong>: Stranger vs. Family/Friends. If Family/Friends, a specific &quot;Relationship Description&quot; is required.</li></ul><hr><h2 id="chat-interface" tabindex="-1">Chat Interface <a class="header-anchor" href="#chat-interface" aria-label="Permalink to &quot;Chat Interface&quot;">​</a></h2><ul><li><strong>Left</strong>: Detailed customer profile sidebar.</li><li><strong>Center</strong>: Main conversation window containing message history.</li><li><strong>Top</strong>: Scenario orientation message and real-time session timer.</li><li><strong>Top Right</strong>: &quot;End Conversation&quot; button.</li></ul><h3 id="safety-rules" tabindex="-1">Safety Rules <a class="header-anchor" href="#safety-rules" aria-label="Permalink to &quot;Safety Rules&quot;">​</a></h3><p>The AI platform employs a content moderation engine.</p><ul><li>Do not send real PII (IDs, phone numbers, etc.).</li><li>Do not attempt jailbreaks or send inappropriate content. Violations will result in the message being blocked immediately.</li></ul><hr><h2 id="sales-stages" tabindex="-1">Sales Stages <a class="header-anchor" href="#sales-stages" aria-label="Permalink to &quot;Sales Stages&quot;">​</a></h2><p>Based on the administrator&#39;s configuration (e.g., Ice-breaking, Needs Discovery, Proposing Options, Handling Objections, Closing).</p><ul><li>Stage assessment is conducted <strong>AFTER</strong> the conversation ends, not in real-time. Do not worry about stage scoring while chatting; just focus on a natural, persuasive flow!</li></ul><hr><h2 id="ending-the-conversation" tabindex="-1">Ending the Conversation <a class="header-anchor" href="#ending-the-conversation" aria-label="Permalink to &quot;Ending the Conversation&quot;">​</a></h2><ul><li><strong>Manual End</strong>: Click the red &quot;End Conversation&quot; button &gt; Confirm.</li><li><strong>Customer-Initiated End</strong>: When the AI customer attempts to hang up or leave, you&#39;ll be prompted to either &quot;Try to Continue&quot; (attempt to keep them engaged) or &quot;Accept End&quot;.</li></ul><p>Once concluded, the system automatically redirects you to the detailed Evaluation Report.</p>',37)])])}const g=t(n,[["render",r]]);export{m as __pageData,g as default};
